from flask import Flask, request, jsonify, abort

app = Flask(__name__)

# Configuration for different environments
ENV_CONFIGS = {
    'dev': {'base_uri': 'http://localhost:5000'},
    'staging': {'base_uri': 'https://staging.example.com'},
    'prod': {'base_uri': 'https://example.com'}
}

# Registered redirect URI base
registered_uri = None

@app.route('/register', methods=['POST'])
def register():
    global registered_uri
    env = request.json.get('env')
    if env not in ENV_CONFIGS:
        abort(400, description="Invalid environment")
    
    registered_uri = ENV_CONFIGS[env]['base_uri']
    return jsonify({"message": "Registered successfully"})

@app.route('/authorize', methods=['POST'])
def authorize():
    redirect_uri = request.json.get('redirect_uri')
    if not redirect_uri.startswith(registered_uri):
        abort(403, description="Invalid redirect URI")
    
    # Simulate authorization logic
    return jsonify({"message": "Authorization successful", "redirect_uri": redirect_uri})

if __name__ == '__main__':
    app.run(debug=True)